DROP TABLE IF EXISTS `heritage_audio`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `heritage_audio` (
  `audio_id` bigint NOT NULL AUTO_INCREMENT COMMENT '音频ID',
  `title` varchar(100) NOT NULL COMMENT '音频标题',
  `audio_url` varchar(500) NOT NULL COMMENT '音频文件路径',
  `item_id` bigint NOT NULL COMMENT '关联展品ID (用于调取3D模型)',
  `waveform_data` text COMMENT '预生成的波形数据 (JSON字符串)',
  `description` text COMMENT '内容解析/唱词',
  `status` char(1) DEFAULT '0' COMMENT '状态 (0正常 1待审核 2下架)',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`audio_id`),
  KEY `idx_item_id` (`item_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='非遗声影共振档案表';
