INSERT INTO `heritage_audio` VALUES (1,'白族三道茶','/profile/upload/2026/02/01/晓晴 - 白族三道茶_L_20260201001023A001.ogg',6,NULL,'白族三道茶 - 晓晴 (张兴萍)\n词：晓晴\n曲：晓晴\n\n云南白家三道茶\n历史悠悠茶文化\n头苦二甜三回味\n美好祝愿孕茶中\n\n云南白家三道茶\n求学经商论婚嫁\n迎宾喜庆不可少\n待客交友礼仪到\n\n白水烧开砂罐烤\n茶叶放入罐中烧\n色如琥珀扑鼻香\n半杯苦茶腹中藏\n\n红糖乳山和桂皮\n茶汤煮好八分满\n酸甜苦辣味俱全\n先苦后甜是人间\n\n白水烧开砂罐烤\n茶叶放入罐中烧\n色如琥珀扑鼻香\n半杯苦茶腹中藏\n\n红糖乳山和桂皮\n茶汤煮好八分满\n酸甜苦辣味俱全\n先苦后甜是人间','0','0','admin','2026-02-01 00:14:35','','2026-02-01 00:14:34');
/*!40000 ALTER TABLE `heritage_audio` ENABLE KEYS */;
UNLOCK TABLES;

