INSERT INTO `heritage_inheritor` VALUES (1,'	段银开',NULL,'1',10,'<p>专精 “扎”，创新 100 余种针法，重建璞真染坊</p>','0','0','','2026-01-03 13:26:22','2026-01-03 13:26:22'),(2,'段树坤',NULL,'2',10,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">专注 “染”，开发天然染料，拓展扎染色彩</div></div><p><br></p>','0','0','','2026-01-03 14:25:24','2026-01-03 14:25:24'),(3,'张翰敏',NULL,'3',10,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">蓝续创始人，打造沉浸式扎染体验 </div></div><p><br></p>','0','0','','2026-01-03 14:26:27','2026-01-03 14:26:27'),(4,'张亚辉',NULL,'1',44,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">大理市白族，传承大本曲说唱艺术</div></div><p><br></p>','0','0','','2026-01-03 14:27:09','2026-01-03 14:27:09'),(5,'杨振华',NULL,'1',44,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">大理市白族，致力于大本曲传承推广</div></div><p><br></p>','0','0','','2026-01-03 14:35:20','2026-01-03 14:35:20'),(6,'段四兴',NULL,'1',11,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">剑川县白族，木雕技艺精湛，推动传统木雕创新</div></div><p><br></p>','0','0','','2026-01-03 14:35:41','2026-01-03 14:35:41'),(7,'杨文焕',NULL,'2',22,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">首创十二生肖童帽，还原多款传统帽饰，带动 200 余人传承</div></div><p><br></p>','0','0','','2026-01-03 14:36:04','2026-01-03 14:36:04'),(8,'赵丕鼎',NULL,'1',41,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">大理市白族，非遗传承推广优秀个人</div></div><p><br></p>','0','0','','2026-01-03 14:36:28','2026-01-03 14:36:28'),(9,'杨琼',NULL,'3',45,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">小吃制作技艺（乳扇制作技艺），上关镇江尾村，制作乳扇经验丰富</div></div><p><br></p>','0','0','','2026-01-03 14:37:12','2026-01-03 14:37:12'),(10,'刘丽湖',NULL,'2',10,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">白族布扎技艺代表性传承人</div></div><p><br></p>','0','0','','2026-01-03 14:39:48','2026-01-03 14:39:48'),(11,'董志明',NULL,'2',13,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">传承剑川白族土陶烧制技艺</div></div><p><br></p>','0','0','','2026-01-03 14:40:13','2026-01-03 14:40:13'),(12,'李树坤',NULL,'2',12,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">传承鹤庆白族银器锻制技艺</div></div><p><br></p>','0','0','','2026-01-03 14:40:39','2026-01-03 14:40:39'),(13,'张恩兰',NULL,'4',22,'<div class=\"ql-code-block-container\" spellcheck=\"false\"><div class=\"ql-code-block\" data-language=\"plain\">宾川萂村，教授白族挎包刺绣等</div></div><p><br></p>','0','0','','2026-01-03 14:41:51','2026-01-03 14:41:51');
