INSERT INTO `heritage_item` VALUES (2,'白族服饰',20,'/profile/upload/2025/12/26/服饰01_20251226163540A003.jpg','/profile/upload/2025/12/31/people_20251231130545A001.glb','白族传统服饰以白色为基调，搭配蓝、黑、红等色彩纹样，风格清新雅致，既体现 “白族” 尚白的文化传统，又融合了地域审美与生活实用性。','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">白族传统服饰的风格脉络，深深植根于其民族发展的漫长进程中，最早可追溯至先秦时期的 “滇僰” 族群服饰遗风 —— 彼时滇中地区的土著族群已形成 “衣麻披葛、尚素色” 的着装特点，这一偏好也成为后世白族 “尚白” 文化的雏形。到南诏国（738-902 年）与大理国（937-1253 年）时期，白族服饰迎来了风格定型的关键阶段：一方面，南诏王室与中原王朝的频繁交流，让中原服饰的交领、右衽、宽袖等剪裁元素融入白族服饰，例如女性上衣的 “右衽大襟” 款式，便与唐代中原女子常服有着明显的传承关联；另一方面，大理国 “政教合一” 的文化氛围，让佛教元素开始渗透到服饰细节中，部分服饰纹样中出现的 “莲花、卷草” 等图案，正是当时佛教盛行的视觉投射。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">宋元至明清时期，白族服饰在地域文化的沉淀中进一步细化：明代推行 “改土归流” 政策后，中原纺织技艺（如棉纺、丝绣）传入白族聚居区，使得服饰的面料从传统麻料拓展为棉、丝混纺，装饰工艺也从简单的印染发展出更精细的 “盘绣”“扣绣”；而清代白族与周边彝族、纳西族的贸易往来，又让服饰配色中融入了彝族的 “红褐”、纳西族的 “青黑” 等色调，形成了 “白为底、彩为饰” 的经典搭配逻辑。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">近现代以来，白族服饰虽受现代服装影响出现简化款式，但核心元素始终得以保留：例如男性的 “白色对襟褂子”，其版型仍延续了南诏时期 “短褐窄袖” 的实用设计（便于田间劳作）；女性的 “绣花围裙” 则传承了大理国时期的刺绣工艺，纹样中 “苍山雪、洱海月” 的地域符号，更是白族对自身生存环境的文化隐喻 —— 可以说，白族服饰的每一处款式、配色与纹样，都是其民族历史、文化信仰与生活方式层层叠加的 “视觉档案”。</span></p><p><br></p>','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">采用</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">手工缝制</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">为核心工艺，辅以白族特色的</span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">扎染、刺绣</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">技法：</span></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">扎染：通过纱、线等工具捆扎布料后染色，形成蓝白相间的自然纹理；</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">刺绣：多以花鸟、几何纹样为主题，用细密针法装饰领口、袖口等部位，兼具装饰性与耐用性。</span></li></ol><p><br></p>',11,1,0,0,0,'0',1,NULL,'admin','2025-12-24 23:10:31','','2026-01-03 00:17:42',NULL),(3,'白族木雕',11,'/profile/upload/2025/12/26/木雕01_20251226163657A004.jpg','/profile/upload/2025/12/27/wood_20251227000914A001.glb','✨ 一木一世界，雕刻白族魂。\n本展品是“木雕之乡”剑川的代表作。采用顶级香樟木，通过多层透雕技艺刻画了一位温婉的白族少女。作品将传统民族服饰与现代雕塑审美融合，是研究白族民俗与木艺美学的重要数字资产。🪵','<p>📜 <strong>千年技艺的时光沉淀</strong></p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>南诏遗风</strong> 🏔️：起源于唐代，作为南诏与大理国时期的宫廷御用技艺，距今已有 1000 多年历史。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>文化交融</strong> 🤝：它不仅保留了白族原始的图腾崇拜，还深度融合了中原汉族的建筑木作工艺，是“南方丝绸之路”文化交流的结晶。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>木匠之乡</strong> 🏛️：剑川木匠自古闻名，曾负责营造故宫、天坛等皇家建筑的精细部件，民间素有“雕刻之魂在剑川”的美誉。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>艺术地位</strong> 🏆：2006 年被列入首批国家级非物质文化遗产名录，成为中华民族建筑与美学的活化石。</li></ol>','<p>🔨 <strong>匠心独运的五大秘法</strong></p><ol><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>选材观纹</strong> 🌲：</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span>严格选取大理高海拔地区的<strong>古香樟木</strong>。木材需经“三干三湿”的自然老化处理，确保木性稳定，且自带一种能够防虫避邪的淡淡清香。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>白描定魂</strong> 🖋️：</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span>老艺人不需图纸，直接在木料上进行“胸有成竹”的构图。每一笔都避开木材的结疤，顺应纹理，确定神态。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>粗坯开山</strong> 🪚：</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span>使用大号凿子进行“减法艺术”。将多余木块切除，确立作品的空间比例，此时已能看出白族服饰飘逸的轮廓感。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>多层透雕</strong> 🪡：</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>这是最惊艳的一步！</strong> 艺人要在不到 2 厘米的深度内，雕刻出 3 到 5 层重叠的图案。头饰上的每一朵花瓣、衣襟上的每一根丝线，都由细如毫发的雕刀刻划而成。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>手工推光</strong> 💎：</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span>拒绝化学漆料。完全依靠天然草木灰和多号棉布进行数万次的物理摩擦，使原木产生一种油脂般的莹润光泽，触感如玉，温润入心。</li></ol>',61,1,2,0,0,'0',1,NULL,'admin','2025-12-26 16:37:47','','2026-03-24 22:06:32',NULL),(4,'白族扎染',10,'/profile/upload/2025/12/26/扎染02_20251226163808A005.jpg',NULL,'白族扎染','<p>白族扎染</p>','<p>白族扎染</p>',7,0,0,1,0,'0',1,NULL,'admin','2025-12-26 16:38:19','','2026-01-27 19:28:26',NULL),(5,'白族三合院',30,'/profile/upload/2025/12/26/民居01_20251226165546A006.jpg','/profile/upload/2025/12/30/三合院_20251230160755A004.glb','🏛️ 白族三合院，又称“三坊一照壁”，是大理白族民居建筑艺术的精髓。它由三座正房和一面装饰精美的照壁围合而成，形成了“封闭而不死、敞亮而不散”的独特空间。\n其特色在于“白墙青瓦、木雕彩绘”，不仅防风防震，更通过照壁将洱海的晨曦反射进院落。这不仅是白族先民对自然环境的智慧适应，更是中华建筑美学中“天人合一”的生动体现。✨','<p>白族三合院的形成历史悠久，是一部浓缩的南诏与大理国文化交融史：</p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>起源与萌芽（唐宋时期）：</strong> 📜</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>早在<strong>南诏国</strong>时期，白族先民受到中原唐代建筑风格的影响，开始从原始的干栏式建筑向土木结构院落转型。随着大理国的建立，这种格局逐渐固定，形成了最初的“坊”式结构。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>演进与定型（明清时代）：</strong> 🏺</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>明代“中原移民”潮带来了江淮地区的民居理念，白族工匠将其与大理多风、多震的地理环境结合。为了抵挡苍山吹来的劲风，白族人创新性地发明了**“照壁”**。到了清代，三合院的装饰工艺（尤其是木雕和泥塑）达到了鼎盛，成为了社会地位和家族荣耀的象征。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>地理基因：</strong> 🏔️</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>大理地处苍山之麓、洱海之滨。三合院通常坐西向东或坐北向南，正房对着照壁。由于大理多西风，照壁能有效阻挡风沙；而当太阳西下时，雪白的照壁又能将阳光折射回阴暗的正房，营造出“金碧辉煌”的采光效果，这就是著名的**“照壁回光”**。</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>文化象征：</strong> 🧧</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>每一座三合院的照壁上通常刻有“清白传家”、“紫气东来”或“琴鹤家声”等字样，这反映了白族人民对儒家礼教的崇尚以及对先祖美德的传承。2008年，**“白族民居建筑技艺”**被列入国家级非物质文化遗产名录。</li></ol><p><br></p>','<p>白族三合院的建造过程被誉为“木石与色彩的交响乐”：</p><ol><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>土木结构（榫卯技术）：</strong> 🏗️</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span>全屋采用上好的杉木或栗木，不露一颗钉子，完全依靠**榫卯（Sǔn Mǎo）**结构咬合。这种结构具有极佳的韧性，使建筑在大理的多震带上稳如泰山。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>三雕一绘（装饰灵魂）：</strong> 🎨</li><li data-list=\"bullet\" class=\"ql-indent-1\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>木雕：</strong> 门窗格心常采用五层透雕，刻画麒麟、凤凰及花卉。</li><li data-list=\"bullet\" class=\"ql-indent-1\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>石雕：</strong> 柱础和阶石选用大理石（苍山石），坚固且纹路优雅。</li><li data-list=\"bullet\" class=\"ql-indent-1\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>泥塑与彩绘：</strong> 在照壁和檐口处进行水墨彩绘，形成“素雅如画”的视觉风格。</li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>照壁工艺：</strong> 墙体采用青砖封砌，表面抹以白灰，并在正中书写家训或绘上山水画，工艺极尽考究。🖌️</li></ol>',63,2,2,1,0,'0',0,NULL,'admin','2025-12-26 16:56:01','','2026-03-30 10:08:53',NULL),(6,'三道茶',15,'/profile/upload/2025/12/26/三道茶_20251226170846A007.jpg','/profile/upload/2026/02/01/book_20260201003710A002.glb','三道茶','<p>三道茶</p>','<p>三道茶</p>',19,2,1,0,0,'0',1,NULL,'admin','2025-12-26 17:09:15','','2026-02-01 00:37:12',NULL),(7,'建筑',30,'/profile/upload/2025/12/26/建筑02_20251226170948A008.jpg','/profile/upload/2025/12/27/architecture_20251227222905A001.glb','白族传统建筑是大理风花雪月里的 “凝固诗画”✨！以 “三坊一照壁”“四合五天井” 为经典布局，白墙黛瓦配雕花门楼，既有江南的雅致，又藏着大理的烟火气，是民族美学与生活智慧的完美融合～','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">白族传统建筑的基因，是中原礼制与西南边地风情在苍山洱海边的千年织就。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">南诏国鼎盛之时（公元 8 世纪），伴随唐王朝的文化输出，中原 “中轴线院落” 的规制翻越秦岭，与白族先民的 “干栏式巢居” 相遇 —— 彼时的建筑虽以夯土为基、原木为架，却已埋下 “天人共生” 的伏笔：房屋依山势而建，坡顶顺应西南季风，天井承接苍山融雪，既保留了部落时代对自然的敬畏，又初显中原建筑的秩序之美。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">宋元以降，大理成为 “茶马古道” 与 “南方丝绸之路” 的交汇节点，商贸的繁荣让建筑美学迎来质变：白族望族开始效仿江南园林的 “移步换景”，在院落中增设 “照壁”—— 这堵墙并非单纯的隔断，而是 “藏风聚气” 的载体，壁面题字 “清白传家”，既呼应了白族尚白的审美，也暗合中原 “耕读传家” 的文脉。至明清，建筑工艺趋于极致：门楼的 “三滴水” 造型（三层错落的飞檐），糅合了唐代建筑的舒展与白族银饰的精巧；“粉墙画壁” 的矿物彩绘，以孔雀蓝、朱砂红铺就山水，将《张胜温画卷》的诗意刻进了民居的肌理。</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">更动人的是它的 “活态传承”：近代以来，哪怕钢筋水泥涌入大理，白族民居仍坚守 “三坊一照壁” 的骨架 —— 只是将传统木窗替换为隔热玻璃，把天井的石砌水槽改成暗藏的排水管道。千年建筑形制里，始终装着当代人的烟火：老人在照壁下晒茶，年轻人在天井里围炉，那些雕花的木梁与新贴的瓷砖，共同写就了 “传统不陈旧，新生不疏离” 的民族生活史诗。</span></p><p><br></p>','<h4><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">1. 院落营构：山水间的秩序美学</span></h4><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">白族建筑以 “三坊一照壁” 为核心形制，其营造暗合 “天圆地方” 的哲思：三栋坐北朝南的 “坊屋” 沿中轴线对称排布，围合出方形天井；空缺的一面立起照壁，既补全了空间的 “围合感”，又借壁面反射天光，让院落即便深居巷陌也明亮如昼。其结构以 “榫卯木架” 为骨：柱与梁以 “燕尾榫” 咬合，不用一钉却能承载百年风雨 —— 如正房的横梁，一头削作燕尾状的凸榫，另一头立柱凿出对应的凹槽，榫头入槽后，再以木楔加固，受力越重，咬合越紧，恰如白族文化里 “共生相携” 的处世智慧。</span></p><h4><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">2. 粉墙画壁：时光磨不灭的留白与浓彩</span></h4><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">“白墙” 是白族建筑的灵魂底色，其工艺堪称 “土木间的炼金术”：取苍山生石灰，以糯米浆、红糖汁拌匀，经 “三抹三晾” 的工序敷于墙面 —— 初抹以粗灰打底，二抹以细灰找平，三抹以 “纸筋灰”（草纸捣碎拌灰）收面，每一层都需晾晒至干透，最终形成的墙面白如凝脂，经风历雨数十年而不皲裂。墙绘则是白墙之上的诗意注脚：画师以矿物颜料为墨，取松烟、朱砂、石青入色，绘山水、花鸟、典故于壁 —— 如照壁中央常绘 “松鹤延年”，边角配 “竹影横斜”，颜料经苍山矿物研磨而成，日光下历百年而不褪色，恰似白族文化里 “历久弥新” 的传承底色。</span></p><h4><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">3. 木作瓦艺：细节里的实用与浪漫</span></h4><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">门窗雕饰</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：选滇西硬木（椿木、楠木）为材，经 “透雕打底、浮雕描形、线雕勾纹” 三法而成：先以凿子镂空木料，透出背后的光影（透雕）；再以刻刀让花纹凸起于木面（浮雕）；最后以细刃勾出花瓣脉络、鸟羽纹理（线雕）。雕成后刷以桐油，既让木质防潮防腐，又让纹理在光线下愈显温润，每一扇窗都是可触摸的 “立体诗”。</span></li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">瓦顶营造</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：以 “筒瓦覆脊、板瓦铺面” 为法：半圆的筒瓦顺屋脊排列，形成排水的 “主渠道”；平展的板瓦沿坡面叠铺，缝隙以灰泥填实 —— 最精巧处是 “翘角”：屋顶檐角处的瓦件向上弯翘，既让建筑形如振翅的飞鸟，又让雨水经翘角导流，落于院落之外，是美学与实用的完美共生。</span></li></ol><p><br></p>',19,1,0,0,0,'0',1,NULL,'admin','2025-12-26 17:10:12','','2026-01-27 19:16:32',NULL),(8,'木雕',11,'/profile/upload/2025/12/26/木雕02_20251226171042A009.jpg',NULL,'木雕','<p>木雕</p>','<p>木雕</p>',24,1,1,0,0,'0',1,NULL,'admin','2025-12-26 17:10:57','','2026-01-27 19:16:30',NULL),(9,'建筑',30,'/profile/upload/2025/12/26/建筑03_20251226171115A010.jpg','/profile/upload/2025/12/30/照壁_20251230160740A003.glb','白族建筑','<p>白族建筑</p>','<p>白族建筑</p>',8,1,2,0,0,'0',1,NULL,'admin','2025-12-26 17:11:37','','2026-01-27 19:34:26',NULL),(10,'白族银胎鎏金茶具',12,'/profile/upload/2025/12/27/R-C_20251227232239A003.jpg','/profile/upload/2025/12/27/teacup_20251227232545A004.glb','这是白族传统金属工艺制品，以银为胎、鎏金饰纹，杯身常刻有白族特色的花鸟、几何纹样，兼具实用功能与民族艺术美感，是白族待客礼仪与工艺技艺结合的代表器物。','<p><span style=\"background-color: rgb(255, 255, 255); color: rgba(0, 0, 0, 0.85);\">白族金属制器技艺可追溯至南诏时期，当时已出现银器锻造工艺；明清时期，随着白族与中原、东南亚的贸易往来，鎏金技法传入并与本土银器工艺融合，银胎鎏金茶具开始成为贵族与商绅的待客用具；近现代以来，这种茶具既保留了传统纹样的文化符号，也在器型上融入了更贴合日常使用的设计，是白族金属工艺传承与演变的实物体现。</span></p>','<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">核心工艺流程为：</span></p><ol><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">制胎塑形</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：以纯银熔铸、捶打为薄胎杯身，通过模具或手工调整器型；</span></li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">鎏金装饰</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：将金汞合金均匀涂抹于杯身纹样区域，经高温烘烤使汞蒸发，金层附着于银胎表面；</span></li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">錾刻纹样</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：用錾子在杯身、杯沿雕刻白族特色的 “山茶花、洱海波纹” 等图案，部分会辅以镂空工艺增加层次；</span></li><li data-list=\"ordered\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">抛光打磨</strong><span style=\"background-color: rgb(255, 255, 255); color: rgb(0, 0, 0);\">：用玛瑙刀等工具抛光表面，使银胎与鎏金部分光泽协调，提升质感。</span></li></ol><p><br></p>',6,1,1,0,0,'0',1,NULL,'admin','2025-12-27 23:25:49','','2026-01-03 13:40:41',NULL),(11,'民居',30,'/profile/upload/2025/12/29/建筑05_20251229190314A001.png',NULL,'民居','<p>民居</p>','<p>民居</p>',2,1,0,0,0,'0',1,NULL,'admin','2025-12-29 19:03:34','','2026-01-03 00:17:42',NULL);
