,\"updateBy\":\"admin\",\"visible\":\"1\"} ','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-26 23:13:48',32),(142,'菜单管理',2,'com.ruoyi.web.controller.system.SysMenuController.edit()','PUT',1,'admin','研发部门','/system/menu','127.0.0.1','内网IP','{\"children\":[],\"component\":\"display/detail\",\"createTime\":\"2025-12-26 23:06:06\",\"icon\":\"color\",\"isCache\":\"0\",\"isFrame\":\"1\",\"menuId\":2027,\"menuName\":\"非遗详情\",\"menuType\":\"C\",\"orderNum\":1,\"params\":{},\"parentId\":0,\"path\":\"exhibit/detail/:id\",\"perms\":\"\",\"routeName\":\"HeritageDetail\",\"status\":\"0\",\"updateBy\":\"admin\",\"visible\":\"1\"} ','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-26 23:20:02',27),(143,'非遗展品',2,'com.ruoyi.heritage.controller.HeritageItemController.edit()','PUT',1,'admin','研发部门','/heritage/heritage_manage','127.0.0.1','内网IP','{\"categoryId\":1,\"coverImage\":\"/profile/upload/2025/12/26/木雕01_20251226163657A004.jpg\",\"craft\":\"<p>白族木雕</p>\",\"createBy\":\"\",\"createTime\":\"2025-12-26 16:37:47\",\"delFlag\":\"0\",\"description\":\"白族木雕\",\"history\":\"<p>白族木雕</p>\",\"isRecommend\":0,\"itemId\":3,\"itemName\":\"白族木雕\",\"likeCount\":0,\"modelFile\":\"/profile/upload/2025/12/27/wood_20251227000914A001.glb\",\"params\":{},\"sortOrder\":0,\"status\":0,\"updateBy\":\"\",\"updateTime\":\"2025-12-27 00:09:27\",\"viewCount\":0} ','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-27 00:09:27',36),(144,'非遗展品',2,'com.ruoyi.heritage.controller.HeritageItemController.edit()','PUT',1,'admin','研发部门','/heritage/heritage_manage','127.0.0.1','内网IP','{\"categoryId\":1,\"coverImage\":\"/profile/upload/2025/12/26/木雕01_20251226163657A004.jpg\",\"craft\":\"<p>🔨 <strong>匠心独运的五大秘法</strong></p><ol><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>选材观纹</strong> 🌲：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>严格选取大理高海拔地区的<strong>古香樟木</strong>。木材需经“三干三湿”的自然老化处理，确保木性稳定，且自带一种能够防虫避邪的淡淡清香。</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>白描定魂</strong> 🖋️：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>老艺人不需图纸，直接在木料上进行“胸有成竹”的构图。每一笔都避开木材的结疤，顺应纹理，确定神态。</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>粗坯开山</strong> 🪚：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>使用大号凿子进行“减法艺术”。将多余木块切除，确立作品的空间比例，此时已能看出白族服饰飘逸的轮廓感。</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>多层透雕</strong> 🪡：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>这是最惊艳的一步！</strong> 艺人要在不到 2 厘米的深度内，雕刻出 3 到 5 层重叠的图案。头饰上的每一朵花瓣、衣襟上的每一根丝线，都由细如毫发的雕刀刻划而成。</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>手工推光</strong> 💎：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>拒绝化学漆料。完全依靠天然草木灰和多号棉布进行数万次的物理摩擦，使原木产生一种油脂般的莹润光泽，触感如玉，温润入心。</li></ol>\",\"createBy\":\"\",\"createTime\":\"2025-12-26 16:37:47\",\"delFlag\":\"0\",\"description\":\"✨ 一木一世界，雕刻白族魂。\\n本展品是“木雕之乡”剑川的代表作。采用顶级香樟木，通过多层透雕技艺刻画了一位温婉的白族少女。作品将传统民族服饰与现代雕塑审美融合，是研究白族民俗与木艺美学的重要数字资产。🪵\",\"history\":\"<p>📜 <strong>千年技艺的时光沉淀</strong></p><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>南诏遗风</strong> 🏔️：起源于唐代，作为南诏与大理国时期的宫廷御用技艺，距今已有 1000 多年历史。</li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>文化交融</strong> 🤝：它不仅保留了白族原始的图腾崇拜，还深度融合了中原汉族的建筑木作工艺，是“南方丝绸之路”文化交流的结晶。</li><','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-27 01:45:16',21),(145,'非遗展品',2,'com.ruoyi.heritage.controller.HeritageItemController.edit()','PUT',1,'admin','研发部门','/heritage/heritage_manage','127.0.0.1','内网IP','{\"categoryId\":2,\"coverImage\":\"/profile/upload/2025/12/26/服饰01_20251226163540A003.jpg\",\"craft\":\"<p>手工缝制并有精美刺绣</p>\",\"createBy\":\"admin\",\"createTime\":\"2025-12-24 23:10:31\",\"delFlag\":\"0\",\"description\":\"白族传统服装以白色为主\",\"favoriteCount\":0,\"history\":\"<p>白族自称\\\"白子\\\"，服饰以白色为尊...</p>\",\"itemId\":2,\"itemName\":\"白族服饰\",\"likeCount\":0,\"modelFile\":\"/profile/upload/model2.glb\",\"params\":{},\"sortOrder\":0,\"status\":0,\"updateBy\":\"\",\"updateTime\":\"2025-12-27 12:39:14\",\"viewCount\":0} ','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-27 12:39:15',64),(146,'非遗展品',2,'com.ruoyi.heritage.controller.HeritageItemController.edit()','PUT',1,'admin','研发部门','/heritage/heritage_manage','127.0.0.1','内网IP','{\"categoryId\":3,\"coverImage\":\"/profile/upload/2025/12/26/建筑03_20251226171115A010.jpg\",\"craft\":\"<p>白族建筑</p>\",\"createBy\":\"\",\"createTime\":\"2025-12-26 17:11:37\",\"delFlag\":\"0\",\"description\":\"白族建筑\",\"favoriteCount\":0,\"history\":\"<p>白族建筑</p>\",\"itemId\":9,\"itemName\":\"建筑\",\"likeCount\":0,\"params\":{},\"sortOrder\":1,\"status\":0,\"updateBy\":\"\",\"updateTime\":\"2025-12-27 12:39:29\",\"viewCount\":0} ','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2025-12-27 12:39:29',15),(147,'非遗展品',2,'com.ruoyi.heritage.controller.HeritageItemController.edit()','PUT',1,'admin','研发部门','/heritage/heritage_manage','127.0.0.1','内网IP','{\"categoryId\":1,\"coverImage\":\"/profile/upload/2025/12/26/木雕01_20251226163657A004.jpg\",\"craft\":\"<p>🔨 <strong>匠心独运的五大秘法</strong></p><ol><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>选材观纹</strong> 🌲：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>严格选取大理高海拔地区的<strong>古香樟木</strong>。木材需经“三干三湿”的自然老化处理，确保木性稳定，且自带一种能够防虫避邪的淡淡清香。</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><strong>白描定魂</strong> 🖋️：</li><li data-list=\\\"ordered\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span>老艺人不需图纸，直接在木料上进行“胸有